'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';

interface Item {
    descripcion: string;
    cantidad: number;
    precioUnitario: number;
    descuento: number;
    tipoItbis: number; // 1=18%, 2=16%, 3=Exento
}

export default function EmitirForm() {
    const router = useRouter();
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    // Basic Form State
    const [tipoEcf, setTipoEcf] = useState(31); // 31: Factura de Crédito Fiscal
    const [rncComprador, setRncComprador] = useState('');
    const [razonSocialComprador, setRazonSocialComprador] = useState('');

    // Items State
    const [items, setItems] = useState<Item[]>([
        { descripcion: '', cantidad: 1, precioUnitario: 0, descuento: 0, tipoItbis: 1 }
    ]);

    const addItem = () => {
        setItems([...items, { descripcion: '', cantidad: 1, precioUnitario: 0, descuento: 0, tipoItbis: 1 }]);
    };

    const removeItem = (index: number) => {
        if (items.length > 1) {
            setItems(items.filter((_, i) => i !== index));
        }
    };

    const updateItem = (index: number, field: keyof Item, value: any) => {
        const newItems = [...items];
        newItems[index] = { ...newItems[index], [field]: value };
        setItems(newItems);
    };

    // Derived calculations
    const totalFacturado = items.reduce((acc, item) => {
        const subtotal = (item.cantidad * item.precioUnitario) - item.descuento;
        const itbis = item.tipoItbis === 1 ? subtotal * 0.18 : (item.tipoItbis === 2 ? subtotal * 0.16 : 0);
        return acc + subtotal + itbis;
    }, 0);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError('');

        try {
            // Assuming api-gateway runs on 3000 and proxying to 3002
            // For local testing, we might need to point to the exact ecf-service port if gateway not running
            const res = await fetch('http://localhost:3002/api/v1/ecf', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    // Tenant ID hardcoded for Sprint 2 testing. Normally comes from JWT/Context.
                    'x-tenant-id': 'b0a8c2f1-9d3e-4f5a-8b1c-7e6d5f4a3b2c'
                },
                body: JSON.stringify({
                    tipoEcf: Number(tipoEcf),
                    rncComprador: rncComprador || undefined,
                    razonSocialComprador: razonSocialComprador || undefined,
                    totalFacturado,
                    items: items.map(item => ({
                        ...item,
                        cantidad: Number(item.cantidad),
                        precioUnitario: Number(item.precioUnitario),
                        descuento: Number(item.descuento),
                        tipoItbis: Number(item.tipoItbis)
                    }))
                })
            });

            if (!res.ok) {
                const data = await res.json();
                throw new Error(data.message || 'Error al emitir el comprobante');
            }

            router.push('/');
            router.refresh();
        } catch (err: any) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-8 divide-y divide-gray-200">
            <div className="space-y-6">
                {error && (
                    <div className="bg-red-50 p-4 rounded-md">
                        <p className="text-sm text-red-700">{error}</p>
                    </div>
                )}

                <div>
                    <h3 className="text-lg leading-6 font-medium text-gray-900">Datos Generales</h3>
                    <div className="mt-6 grid grid-cols-1 gap-y-6 gap-x-4 sm:grid-cols-6">
                        <div className="sm:col-span-3">
                            <label htmlFor="tipoEcf" className="block text-sm font-medium text-gray-700">Tipo de e-CF</label>
                            <div className="mt-1">
                                <select
                                    id="tipoEcf"
                                    value={tipoEcf}
                                    onChange={e => setTipoEcf(Number(e.target.value))}
                                    className="shadow-sm focus:ring-blue-500 focus:border-blue-500 block w-full sm:text-sm border-gray-300 rounded-md py-2 border px-3 bg-white"
                                >
                                    <option value={31}>e-CF (31) Factura de Crédito Fiscal</option>
                                    <option value={32}>e-CF (32) Factura de Consumo</option>
                                    <option value={34}>e-CF (34) Nota de Crédito</option>
                                </select>
                            </div>
                        </div>

                        <div className="sm:col-span-3">
                            <label htmlFor="rncComprador" className="block text-sm font-medium text-gray-700">RNC/Cédula Comprador</label>
                            <div className="mt-1">
                                <input
                                    type="text"
                                    id="rncComprador"
                                    value={rncComprador}
                                    onChange={e => setRncComprador(e.target.value)}
                                    className="shadow-sm focus:ring-blue-500 focus:border-blue-500 block w-full sm:text-sm border-gray-300 rounded-md py-2 px-3 border"
                                />
                            </div>
                        </div>

                        <div className="sm:col-span-6">
                            <label htmlFor="razonSocialComprador" className="block text-sm font-medium text-gray-700">Razón Social Comprador</label>
                            <div className="mt-1">
                                <input
                                    type="text"
                                    id="razonSocialComprador"
                                    value={razonSocialComprador}
                                    onChange={e => setRazonSocialComprador(e.target.value)}
                                    className="shadow-sm focus:ring-blue-500 focus:border-blue-500 block w-full sm:text-sm border-gray-300 rounded-md py-2 px-3 border"
                                />
                            </div>
                        </div>
                    </div>
                </div>

                <div className="pt-8">
                    <div className="flex justify-between items-center mb-4">
                        <h3 className="text-lg leading-6 font-medium text-gray-900">Ítems de Factura</h3>
                        <button
                            type="button"
                            onClick={addItem}
                            className="inline-flex items-center px-3 py-1.5 border border-transparent text-xs font-medium rounded-md text-blue-700 bg-blue-100 hover:bg-blue-200"
                        >
                            + Añadir Ítem
                        </button>
                    </div>

                    <div className="space-y-4">
                        {items.map((item, index) => (
                            <div key={index} className="grid grid-cols-12 gap-4 items-center bg-gray-50 p-4 border border-gray-200 rounded-md">
                                <div className="col-span-12 sm:col-span-4">
                                    <label className="block text-xs font-medium text-gray-700">Descripción</label>
                                    <input
                                        type="text"
                                        required
                                        value={item.descripcion}
                                        onChange={e => updateItem(index, 'descripcion', e.target.value)}
                                        className="mt-1 block w-full shadow-sm sm:text-sm border-gray-300 rounded-md px-2 py-1.5 border"
                                    />
                                </div>
                                <div className="col-span-6 sm:col-span-2">
                                    <label className="block text-xs font-medium text-gray-700">Cantidad</label>
                                    <input
                                        type="number"
                                        min="1"
                                        required
                                        value={item.cantidad}
                                        onChange={e => updateItem(index, 'cantidad', parseFloat(e.target.value))}
                                        className="mt-1 block w-full shadow-sm sm:text-sm border-gray-300 rounded-md px-2 py-1.5 border"
                                    />
                                </div>
                                <div className="col-span-6 sm:col-span-2">
                                    <label className="block text-xs font-medium text-gray-700">Precio Unit.</label>
                                    <input
                                        type="number"
                                        min="0"
                                        step="0.01"
                                        required
                                        value={item.precioUnitario}
                                        onChange={e => updateItem(index, 'precioUnitario', parseFloat(e.target.value))}
                                        className="mt-1 block w-full shadow-sm sm:text-sm border-gray-300 rounded-md px-2 py-1.5 border"
                                    />
                                </div>
                                <div className="col-span-6 sm:col-span-2">
                                    <label className="block text-xs font-medium text-gray-700">ITBIS</label>
                                    <select
                                        value={item.tipoItbis}
                                        onChange={e => updateItem(index, 'tipoItbis', parseInt(e.target.value))}
                                        className="mt-1 block w-full shadow-sm sm:text-sm border-gray-300 rounded-md px-2 py-1.5 border bg-white"
                                    >
                                        <option value={1}>18%</option>
                                        <option value={2}>16%</option>
                                        <option value={3}>Exento</option>
                                    </select>
                                </div>
                                <div className="col-span-6 sm:col-span-2 flex justify-end">
                                    <button
                                        type="button"
                                        onClick={() => removeItem(index)}
                                        disabled={items.length === 1}
                                        className="mt-5 text-red-600 hover:text-red-900 disabled:opacity-50 text-sm font-medium"
                                    >
                                        Eliminar
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>

                    <div className="mt-8 border-t border-gray-200 pt-5 pr-4 flex justify-end">
                        <dl className="space-y-2 text-sm">
                            <div className="flex justify-between font-medium text-gray-900 text-xl">
                                <dt className="mr-6">Total a Pagar DOP:</dt>
                                <dd>${totalFacturado.toFixed(2)}</dd>
                            </div>
                        </dl>
                    </div>
                </div>
            </div>

            <div className="py-5">
                <div className="flex justify-end">
                    <button
                        type="button"
                        onClick={() => router.push('/')}
                        className="bg-white py-2 px-4 border border-gray-300 rounded-md shadow-sm text-sm font-medium text-gray-700 hover:bg-gray-50"
                    >
                        Cancelar
                    </button>
                    <button
                        type="submit"
                        disabled={loading}
                        className="ml-3 inline-flex justify-center py-2 px-4 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-blue-600 hover:bg-blue-700 disabled:opacity-50"
                    >
                        {loading ? 'Emitiendo...' : 'Emitir e-CF y Firmar XML'}
                    </button>
                </div>
            </div>
        </form>
    );
}
